mapper.select:
SELECT COUNT(*)
  FROM BL_COMMENT_REPORTS
 WHERE COMMENT_ID = #{commentId}
   AND REPORTER_ID = #{reporterId}

SELECT r.REPORT_ID AS reportId, r.COMMENT_ID AS commentId, r.REPORTER_ID AS reporterId, reporter.NICKNAME AS reporterNickname, r.REASON_TYPE AS reasonType, r.REASON_TEXT AS reasonText, r.STATUS AS status, r.HANDLED_BY AS handledBy, handler.NICKNAME AS handledByNickname, TO_CHAR(r.HANDLED_AT, 'YYYY-MM-DD HH24:MI') AS handledAt, TO_CHAR(r.CREATED_AT, 'YYYY-MM-DD HH24:MI') AS createdAt, c.PRODUCT_ID AS productId, c.CONTENT AS commentContent, c.STATUS AS commentStatus, p.PRODUCT_NAME AS productName FROM BL_COMMENT_REPORTS r JOIN BL_PRODUCT_COMMENTS c ON r.COMMENT_ID = c.COMMENT_ID JOIN BL_PRODUCTS p ON c.PRODUCT_ID = p.PRODUCT_ID JOIN BL_MEMBERS reporter ON r.REPORTER_ID = reporter.MEMBER_ID LEFT JOIN BL_MEMBERS handler ON r.HANDLED_BY = handler.MEMBER_ID
AND r.STATUS = #{status}
ORDER BY r.REPORT_ID DESC FETCH FIRST #{size} ROWS ONLY
